var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"대회의실, 호텔 아르마다, 샤레이드 지점\\n<color=#ffd34c>크리스티나 브레히트 중사</color>, 연관자 면담 중\\n사태 종료 후 ██시간째.","JPN":"大会議室、ホテルアルマダ、シャレード支店\\n<color=#ffd34c>クリスティーナ・ブレヒト軍曹</color>、関係者面談中\\n事態終了後██時経過。","ENG":"Conference Room, Hotel Armada, Charade branch\\n<color=#ffd34c>Sergeant Christina Brecht</color>, interviewed ██ hours after the incident.","TWN":"大會議室，艾魯瑪達飯店，查雷德據點\\n<color=#ffd34c>克莉絲蒂娜·布萊希特中士</color>，相關人士面談中\\n事件結束後第██個小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"올바른 보도, 진실된 정보. 그로니아 국영 뉴스입니다.","JPN":"正しい報道、真なる情報。グロニア国営ニュースです。","ENG":"Reporting in with the truth, Gronia National News.","TWN":"真實的報導，正確的資訊，格羅尼亞國境新聞。"},"stage":{"bg":"HARMONY_01_2","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"건국절 기념식의 충격이 채 가시지 않았지만, 온건파 반군은 재난 구획 복구를 지원할 용의가 있다고 밝혔습니다.","JPN":"建国記念式の衝撃がまだ消えておりませんが､反乱軍の穏健派は災難区画の復興を手伝う意向があることを表明しました。","ENG":"The shock of the National Foundation Day incident has not subsided, but the moderate rebels have said they are willing to help rebuild the disaster zone.","TWN":"雖然國慶典禮依舊餘波盪漾，但溫和派叛軍表示有意協助重建災難區劃。"},"stage":{"bg":"HARMONY_01_2","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"평화 협정에서 유리한 고지를 차지하기 위한 것으로 보이는 제스처이나, 정부는 이를 환영하며…….","JPN":"平和協定で有利な立場に立つためのものと思われますが､政府はこれを歓迎し……","ENG":"The government welcomes the assistance, though the gesture appears to be aimed at gaining an advantage in the peace agreement.","TWN":"似乎是希望藉此在和平協議中取得優勢，但政府表示歡迎……"},"stage":{"bg":"HARMONY_01_2","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 치. 기껏 샤레이드에 왔는데 이게 뭐람.","JPN":"チッ。せっかくシャレードに来たのに何なのよ。","ENG":" Tch. I made it to the Charade, but what a bummer.","TWN":" 嘖，好不容易來一趟查雷德，結果這是怎樣？！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 대표는 오자마자 일 있다고 나가 버려, 용돈도 안 줘서 싸구려 여관 방에서 한 발짝도 못 나가. ","JPN":"代表は着いてすぐに仕事で出かけるし、お小遣いもくれないから安っぽい宿から一歩も出られないし。 ","ENG":"Boss left for work as soon as arrived. And she didn't even give me an allowance, so I can’t step out of this shabby hotel room. ","TWN":"BOSS一來就說有事要忙完全不見人影，也沒留零用錢給我，害我只能待在便宜旅館裡！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 미안하다는 생각 안 들어, 호라이즌?","JPN":"悪いと思わない､ホライズン？","ENG":" Don’t you feel sorry, Horizon?","TWN":"地平線，你都不會不好意思嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":" 레이첼이 따라와서 발생한 추가 지출을 감안하면 80시간 동안 식사를 수돗물로 대체해도 무방할 겁니다.","JPN":"レイチェルがついてきて発生した追加支出を考えると、80時間分の食事を水道水に変えても問題ないところです。","ENG":" Given additional expenses caused by you, it would be reasonable to replace the meals with tap water for 80 hours.","TWN":"想到你跟來之後會產生的額外支出，可能有80小時都只能喝自來水果腹。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":" 그리고 월급 꼬박꼬박 수령하는 휴먼이 용돈을 요구하지 마십시오.","JPN":"それに毎月給料をもらっているヒューマンはお小遣いを要求しないでください。","ENG":" And you receive your salary on a regular basis. Don’t expect to get an allowance.","TWN":"而且按時領薪水的人類還要求什麼零用錢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 에휴. 한마디도 안 지지, 하여튼.","JPN":"はあ。一言も負けてくれないんだから、まったく。","ENG":" Ugh… You're always trying to score off me.","TWN":"真是的，我講一句你頂十句。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" ……그런데 진짜 어디 갔다 온 거야? ","JPN":"……で、本当にどこ行ってきたの？ ","ENG":" …Anyway, where have you really been? ","TWN":" ……你說你到底是去哪裡？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":" 여행에서 만난 친구들이라더니 하나같이 본새가 장난 아닌데?","JPN":"旅行であった友達って言ってたけど、全員ヤバい格好してるよ？","ENG":" Are these the ones you met on your journey? They look quite fierce.","TWN":"你說是旅行中遇到的朋友，每個長得都非等閒之輩呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"실물을 보니 친구 분 패션도 어떤 의미에서는 파격적이군요, 호라이즌 양.","JPN":"実物を見るとご友人のファッションもある意味では型破りですわね、ホライズンさん。","ENG":"Now that I see her in person, your friend’s fashion sense is rather unconventional, Horizon.","TWN":"見到本人後，發現你朋友的時尚品味算是滿特別的呢，地平線。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"남 말 하지 마십시오. 엘리자베스.","JPN":"人のことを言わないでください、エリザベス。","ENG":"Talk about yourself, Elizabeth.","TWN":"你還敢說別人，伊莉莎白。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"오면서 보니까 이 도시는 진짜 평화롭더라고요. 그냥 눌러앉고 싶어질 정도로요.","JPN":"来る途中で見たら、この街は本当に平和でした。居座りたくなるくらいにですね。","ENG":"Seeing it on the way here, this city seems so peaceful. I’d love to settle down here.","TWN":"來的路上覺得這座城市真的好和平喔，真想在這裡定居。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당분간은 싫어도 여기서 지내야 할 거야.","JPN":"しばらくは嫌でもここで暮らすことになるよ。","ENG":"Well, you’ll have to stay here for a while even if you don’t like it.","TWN":"就算你不想也得暫時待在這裡，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"마에스트로 그 개자식이 너랑 아주머니를 점찍었으니까.","JPN":"マエストロ、あのくそ野郎があなたとおばさんを狙っているからね。","ENG":"Maestra, that bastard, has her eyes on you and the madam.","TWN":"誰叫指揮家盯上你和伯母。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……하긴, 생지옥행 특급열차 티켓을 강매당하긴 했죠.","JPN":"……まあ、生地獄行きの特急列車チケットを押し売りされはしましたね。","ENG":"Well... Looks like I was forced to buy a one way express ticket to hell.","TWN":"……也是，根本就是強迫中獎。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……모여서 한가하게 담소나 나눌 심산이었던가. ","JPN":"……集まってのんきに話でもするつもりだったか。 ","ENG":"...Have we gathered for nothing more than a leisurely discussion. ","TWN":"……大家聚集於此是要閒話家常嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로를 추격하지 않겠다면, 나는 이만 가겠다.","JPN":"マエストロを追うつもりがないというなら、我はこれにて失礼しよう。","ENG":"If we will not give Maestra pursuit, I shall take my leave.","TWN":"如果沒有要追擊指揮家，恕我告辭。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"기다려라. 모르스. ","JPN":"待て、モールス。 ","ENG":"Wait. Mors. ","TWN":"等一下，莫爾斯。 "},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"뭔가. 스스로 안식을 거부한 자여.","JPN":"なんだ。自ら安息を拒んだ者よ。","ENG":"What is it, one who refuses rest?","TWN":"什麼事，拒絕進入安息的人？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"한 명의 전력이 아쉬운 상황에 그 상태로 마에스트로를 추격하는 것은 이적행위다.","JPN":"一人の戦力でも惜しい状況で、そのままマエストロを追うことは利敵行為だ。","ENG":"One person cannot do it alone. Going after Maestra alone in your state would only benefit her.","TWN":"在失去一個戰力狀況下去追擊指揮家，無疑是去送死。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"분명히 말하지. 셰나 하나만으로도 상대하기 벅찬 것 아닌가?","JPN":"はっきり言おう。シェナだけでも手ごわいのではないか？","ENG":"Be honest. You would not be able to handle even Shena on your own, would you?","TWN":"我就直說吧，光是對付世娜一個，就已經很吃力不是嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"표면적으로 움직이던 단원은 분명 셰나뿐이었죠. ","JPN":"表面的に動いていた団員は確かシェナだけでしたわね。 ","ENG":"The member that moved on the surface was definitely Shena alone.","TWN":"表面上只有世娜一個團員在行動，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 이번에 확인된 바와 같이, 추격을 피한 최고 단원들은 분명 존재합니다.","JPN":"しかし今回確認されたように、追撃を避けた首席奏者はきっと存在していますわ。","ENG":"However, we now know for certain this time, that there are definitely other Elite Members who have escaped us.","TWN":"但就如果這次所掌握到的，一定還有其他未露面的首席樂手。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"심지어 카르멘은 한 번 핵을 파괴했어. 다른 녀석들은 몰라도 걔는 확실해.","JPN":"しかもカルメンは一回核を破壊されたの。他の連中は知らないけど、あいつだけは確かだわ。","ENG":"We’ve even destroyed Carmen’s core once. I am not sure about the others, but I am sure about her.","TWN":"其他人我不確定，但我明明就有破壞掉卡門的核心。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그런데 그 가증스러운 년이……. 앨리스 전대장 몸으로 나타난 거야.","JPN":"なのに、あの憎たらしい女が……アリス戦隊長の体で現れたのよ。","ENG":"But that despicable woman... appeared in the body of Commander Alice.","TWN":"那可惡的女人……竟然借艾莉絲戰隊長的身體還魂。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"만약 그 몸이 정말 앨리스 전대장의 것이라면, 적어도 우리들 손으로 장례를 치러야 옳겠지.","JPN":"もしその体が本当にアリス戦隊長のものであれば、せめて私たちの手で葬儀を行うべきでしょうね。","ENG":"If that really is Alice’s body, at the very least we should give her a funeral ourselves.","TWN":"若那個身體真的是艾莉絲戰隊長的，那我們至少該替她辦個喪禮吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"표현은 과격하지만 그 점은 나 역시 공감한다, 알렉스.","JPN":"過激な表現だが、その点には私も同意する、アレックス。","ENG":"The way you expressed it was a bit extreme, but I agree with that, Alex.","TWN":"雅蕾克絲，雖然你的表達方式有點激動，但這一點我也認同。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"결과적으로 그로니아는 현대에 전례 없는 침식 청정구역이 된 모양이더군요.","JPN":"結果的にグロニアは現代において前例のない侵食清浄区域になったみたいですね。","ENG":"As a result, Gronia seems to have become an area with no corruption, the likes of which we have never seen before.","TWN":"就結論而言，格羅尼亞現在算是處於前所未有的侵蝕清潔狀態吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"고작해야 몇 년이라도 나라에 큰 변화가 일어나기엔 충분한 시간이에요.","JPN":"たかが何年でも、国に大きな変化を起こすには十分な時間ですわ。","ENG":"Even if only for a few years, they will have time enough to enact major change in the country.","TWN":"不出幾年，這個國家就會發生很大的變化。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래서 지금 잘됐다는 거예요?","JPN":"それで、めでたいってことですか？","ENG":"So you’re saying everything’s good now?","TWN":"這是好的意思嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"타인의 말은 끝까지 경청하도록 하세요, 오빠 대신 입대 지원했던 크리스티나 브레히트 중사.","JPN":"人の言うことは最後まで聞くようにしてください。お兄さんの代わりに入隊したクリスティーナ・ブレヒト軍曹。","ENG":"Do try to listen to others until they are finished speaking, Sergeant Christina Brecht, who applied to join the army in the place of her brother.","TWN":"請把話聽完，代兄從軍的克莉絲蒂娜·布萊希特中士。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"기, 기분 나빠…… 스토커세요?","JPN":"き、キモっ……ストーカーですか？","ENG":"Eww, creepy... Are you a stalker or what?","TWN":"可惡……你是跟蹤狂嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"요지는 정부와 학회의 배후 단합으로 추진되었던 일이란 뜻이지.","JPN":"結局は政府と学会の根回しで進められた事というわけね。","ENG":"The main point being that it was secretly promoted by cooperation between the government and the Society.","TWN":"重點就是政府和學會私下聯手推動的事，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"학회는 엘리시움 필하모닉의 재건을. 그로니아는 침식 현상으로부터의 단기적인 안전을.","JPN":"学会はエリシウムフィルハーモニーの再建を。グロニアは侵食現象からの短期的な安全を。","ENG":"The Society wanted reconstruction of the Elysium Philharmonic. Gronia wanted temporary safety from Corruption.","TWN":"像是學會幫助愛樂組織東山再起，還有讓格羅尼亞在侵蝕現象中有短暫的安全，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"수도까지 침식체들에게 위협 받던 처지였으니 알 만해.","JPN":"首都まで侵食体に脅かされたんだから、わかるわ。","ENG":"Even the capital was threatened by Corruption, so it is understandable.","TWN":"甚至是讓首都受到侵蝕體的威脅。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러니 마에스트로에 대한 문제를 해결하려면 학회와 한 번은 엮이는 수밖에 없으려나.","JPN":"だからマエストロの問題を解決するには学会と一度関わるしかないかな。","ENG":"So, in order to solve the problem of Maestra, we’ll need to get tangled up with the Society.","TWN":"因此要解決指揮家的問題，就勢必會和學會牽扯上。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어……. 말씀만 듣고도 별로 엮이면 안 되는 작자들이라는 건 감이 오네요.","JPN":"はあ……話だけ聞いてもあまり関わらない方がいい連中だって言うことはわかりますね。","ENG":"Huh... I can already tell from the way you’re speaking that it’s safe not to get involved.","TWN":"呃……聽你們說完，好像不要跟那些傢伙扯上關係比較好。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데 결국 여기 있는 사람들이 죄다 달려들었는데도 마에스트로 상대로 위태위태하지 않았어요?","JPN":"でも、結局ここにいる全員が応戦したのにマエストロ相手に危なかったですよね？","ENG":"But in the end, weren’t we in danger against Maestra even when all the people here attacked?","TWN":"但就算大家都聚集在一起，不是也不足以對付指揮家嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨는……. 이런 식으로 되길 원하지 않았을 텐데요.","JPN":"レヴナントさんは……こんな風になることを望んでなかったはずですが。","ENG":"Revenant... wouldn’t have wanted it to be this way.","TWN":"亡靈小姐……應該也不希望變成這樣吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그 부분에 대해 할 얘기가 있다. 중사.","JPN":"それについて、話がある。軍曹。","ENG":"I have something to say on that matter, Sergeant.","TWN":"中士，關於這件事我有話要跟你說。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"중사, 예상컨대 너만이 할 수 있는 일이야.","JPN":"おそらく、君だけができることだ。","ENG":"Sergeant, I expect that you are the only one who can do it.","TWN":"這件事只有你辦得到。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...Huh?","TWN":"……什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음? 내가 뭔가 이상한 말이라도 했나?","JPN":"うむ？　何か変なことでも言ったか？","ENG":"Oh? Did I say something weird?","TWN":"嗯？我有說什麼奇怪的話嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 아뇨. 그냥…….","JPN":"あ、いいえ。ただ……","ENG":"Ah, no. It’s just...","TWN":"喔，沒有，只是……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……마침 듣고 싶던 말이라서요.","JPN":"……ちょうど聞きたかったことでしたので。","ENG":"...Something I’ve wanted to hear at this point.","TWN":"……那正好是我想聽到的話。"},"stage":{"bg":"HARMONY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래서, 제가 뭘 하면 되죠?","JPN":"それで、私が何をすればいいんですか？","ENG":"So, what do you need me to do?","TWN":"所以是要我做什麼？"},"stage":{"bg":"HARMONY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};